import{_ as t,a,b as o,c as i,d as s}from"./chunks/sidebar-usage-limit.BZbSXi96.js";import{_ as n}from"./chunks/common-target-settings.CA2Xo8wE.js";import{_ as r}from"./chunks/sidebar-schedule-dates.DTnHEJAO.js";import{_ as l,a as c}from"./chunks/common-product-discount-message-format.BUy9b524.js";import{_ as p,c as u,o as d,ag as h}from"./chunks/framework.B58IbkZx.js";const g="/1.0.0-PRO/assets/selection-scheduled.B-81BOQC.png",m="/1.0.0-PRO/assets/scheduled-discount-percentage.DB_18Ngx.png",f="/1.0.0-PRO/assets/scheduled-discount-fixed.CQSMxV0G.png",S="/1.0.0-PRO/assets/scheduled-display-as-regular-price.z-QjObxH.png",O=JSON.parse('{"title":"Campaign Type: Scheduled Discount","description":"","frontmatter":{},"headers":[],"relativePath":"campaigns/scheduled-discounts.md","filePath":"campaigns/scheduled-discounts.md","lastUpdated":1769871666000}'),b={name:"campaigns/scheduled-discounts.md"};function y(_,e,T,v,x,P){return d(),u("div",null,e[0]||(e[0]=[h('<h1 id="campaign-type-scheduled-discount" tabindex="-1">Campaign Type: Scheduled Discount <a class="header-anchor" href="#campaign-type-scheduled-discount" aria-label="Permalink to &quot;Campaign Type: Scheduled Discount&quot;">​</a></h1><p>A <strong>Scheduled Discount</strong> is the most common and straightforward type of campaign. It allows you to apply a direct price reduction (either a fixed amount or a percentage) to products for a specific, pre-defined period.</p><p>This is the perfect tool for running classic sales events like:</p><ul><li>Weekend Flash Sales</li><li>Holiday Promotions (e.g., Black Friday, New Year&#39;s)</li><li>Seasonal or End-of-Season Clearance Sales</li></ul><p>This guide will walk you through creating a Scheduled Discount step by step.</p><h2 id="step-1-select-your-campaign-type" tabindex="-1">Step 1: Select Your Campaign Type <a class="header-anchor" href="#step-1-select-your-campaign-type" aria-label="Permalink to &quot;Step 1: Select Your Campaign Type&quot;">​</a></h2><p>To begin, navigate to <strong>CampaignBay → Add Campaign</strong>.</p><p><img src="'+g+'" alt="Select Campaign Type"></p><ul><li><strong>Select Discount Type:</strong> Choose <strong><code>Scheduled Discount</code></strong> from the list. This configures the campaign to apply a simple, direct price reduction.</li></ul><p><img src="'+t+'" alt="Campaign Title"></p><ul><li><strong>Campaign Title:</strong> Give your campaign a clear and descriptive name (e.g., &quot;Summer Weekend Sale&quot;).</li></ul><p><img src="'+a+'" alt="Save Actions"></p><ul><li><strong>Select Status:</strong><ul><li><strong>Active:</strong> The campaign will be live as soon as its start time is reached.</li><li><strong>Inactive:</strong> The campaign will be saved as a draft.</li></ul></li></ul><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>For scheduled campaigns, set the Status to <strong>Active</strong> and enable the schedule. The system will display a <strong>Scheduled</strong> label in the campaign list until the start time is reached.</p></div><h2 id="step-2-set-the-discount-target" tabindex="-1">Step 2: Set the Discount Target <a class="header-anchor" href="#step-2-set-the-discount-target" aria-label="Permalink to &quot;Step 2: Set the Discount Target&quot;">​</a></h2><p>This crucial step defines which products in your store are eligible for the discount.</p><p><img src="'+n+'" alt="Discount Target"></p><p>The <strong>DISCOUNT TARGET</strong> dropdown provides powerful options to control the scope of your campaign, such as applying it to the entire store, specific products, or categories.</p><div class="info custom-block"><p class="custom-block-title">Learn More About Targeting</p><p>The &quot;Discount Target&quot; setting is a powerful feature shared by all campaign types. We&#39;ve created a dedicated guide to explain all of its options and conditional fields in detail.</p><p><strong><a href="./../core-concepts/targeting.html">Read the Full Guide: Targeting →</a></strong></p></div><h2 id="step-3-define-the-discount-value" tabindex="-1">Step 3: Define the Discount Value <a class="header-anchor" href="#step-3-define-the-discount-value" aria-label="Permalink to &quot;Step 3: Define the Discount Value&quot;">​</a></h2><p>This is where you set the actual discount amount the customer will receive.</p><h3 id="_1-percentage-discount" tabindex="-1">1. Percentage Discount <a class="header-anchor" href="#_1-percentage-discount" aria-label="Permalink to &quot;1. Percentage Discount&quot;">​</a></h3><p><img src="'+m+'" alt="Percentage Discount"></p><ul><li><strong>Percentage %:</strong> Select this mode and enter the numeric value (e.g., <code>40</code>) to take a percentage off the product&#39;s price.</li></ul><h3 id="_2-fixed-amount-discount" tabindex="-1">2. Fixed Amount Discount <a class="header-anchor" href="#_2-fixed-amount-discount" aria-label="Permalink to &quot;2. Fixed Amount Discount&quot;">​</a></h3><p><img src="'+f+'" alt="Fixed Discount"></p><ul><li><strong>Fixed ($) per Item:</strong> Select this mode and enter the numeric value to deduct a fixed currency amount from <strong>each individual item</strong>.</li></ul><h2 id="step-4-set-conditions-optional" tabindex="-1">Step 4: Set Conditions (Optional) <a class="header-anchor" href="#step-4-set-conditions-optional" aria-label="Permalink to &quot;Step 4: Set Conditions (Optional)&quot;">​</a></h2><p>You can add specific rules to restrict who can use this discount (e.g., specific User Roles).</p><p><img src="'+o+'" alt="Conditions Overview"></p><p><strong><a href="./../core-concepts/conditions.html">Read the Full Guide: How to Use Conditions →</a></strong></p><h2 id="step-5-set-other-configurations-optional" tabindex="-1">Step 5: Set Other Configurations (Optional) <a class="header-anchor" href="#step-5-set-other-configurations-optional" aria-label="Permalink to &quot;Step 5: Set Other Configurations (Optional)&quot;">​</a></h2><p>This section provides additional rules for your campaign.</p><p><img src="'+i+'" alt="Exclude Sale Item"></p><ul><li><strong>Exclude Sale Items:</strong> Check this box if you do not want this campaign&#39;s discount to apply to products that are already on sale in WooCommerce. This is useful for preventing &quot;double discounting.&quot;</li></ul><p><img src="'+s+'" alt="Enable Usage Limit"></p><ul><li><strong>Enable Usage Limit:</strong> Check this box to set a maximum number of times this campaign can be used across your entire store. Once the limit is reached, the campaign will automatically become inactive.</li></ul><h2 id="step-6-set-the-schedule-optional" tabindex="-1">Step 6: Set the Schedule (Optional) <a class="header-anchor" href="#step-6-set-the-schedule-optional" aria-label="Permalink to &quot;Step 6: Set the Schedule (Optional)&quot;">​</a></h2><p>For a Scheduled Discount, setting the duration is essential. This section controls when your campaign will automatically start and end.</p><p><img src="'+r+'" alt="Enable Schedule"></p><ul><li><strong>Start Time / End Time:</strong> Use the date and time pickers to set the exact moment for the campaign to activate and expire.</li></ul><div class="tip custom-block"><p class="custom-block-title">Timezone Information</p><p>All dates and times are based on the timezone you have configured in your main WordPress settings under <strong>Settings → General → Timezone</strong>. The system automatically handles all UTC conversions for you.</p></div><div class="info custom-block"><p class="custom-block-title">Learn More About Automation</p><p>The status of your campaign is closely tied to the scheduling system, which uses WordPress Cron to automate activation and expiration.</p><p><strong><a href="./../core-concepts/scheduling-and-automation.html">Read the Full Guide: Scheduling &amp; Automation →</a></strong></p></div><h2 id="step-7-display-configurations" tabindex="-1">Step 7: Display Configurations <a class="header-anchor" href="#step-7-display-configurations" aria-label="Permalink to &quot;Step 7: Display Configurations&quot;">​</a></h2><p>This section controls how the offer is communicated to the customer, both on the product page and in their cart.</p><p><img src="'+S+'" alt="Display as Regular Price"></p><ul><li><strong>Display as Regular Price:</strong> If checked, the discounted price will be shown as the regular price on the product page, rather than showing a &quot;sale&quot; price with a strikethrough.</li></ul><p><img src="'+l+'" alt="Show Promotional Message"></p><ul><li><strong>Show Product Page Promotional Message:</strong> Toggle this to enable or disable the custom message on the product pages.</li></ul><p><img src="'+c+'" alt="Product Page Promotional Message Format"></p><ul><li><p><strong>Product Page Discount Message Format:</strong> Customize the promotional text using placeholders like <code>{percentage_off}</code> or <code>{amount_off}</code>.</p><ul><li><em>Example:</em> <code>Flash Sale! Get {percentage_off}% off today!</code></li></ul></li><li><p><strong>Cart Page Discount Message Format:</strong> Enter a message to display on the cart page when the discount is applied.</p><ul><li><em>Example:</em> <code>Discount applied: {discount_amount}</code></li></ul></li><li><p><strong>Cart Page Message Location:</strong> Choose where the cart message should appear (e.g., next to the line item name).</p></li></ul><h2 id="step-8-save-the-campaign" tabindex="-1">Step 8: Save the Campaign <a class="header-anchor" href="#step-8-save-the-campaign" aria-label="Permalink to &quot;Step 8: Save the Campaign&quot;">​</a></h2><p>Once you have configured all the options, click the <strong>Save Campaign</strong> button at the top right or the <strong>Save Changes</strong> button at the bottom of the page. After saving, you will be redirected back to the &quot;All Campaigns&quot; list, where you can see your new campaign.</p><h2 id="next-steps" tabindex="-1">Next Steps <a class="header-anchor" href="#next-steps" aria-label="Permalink to &quot;Next Steps&quot;">​</a></h2><p>Now that you&#39;ve mastered the Scheduled Discount, learn how to create campaigns that reward customers for buying in bulk.</p><ul><li><strong><a href="./quantity-discounts.html">Creating a Quantity Based Discount →</a></strong></li></ul>',56)]))}const A=p(b,[["render",y]]);export{O as __pageData,A as default};
